import streamlit as st
import base64

st.set_page_config(
    page_title="Conciliação Contábil",
    page_icon="📊",
    layout="wide",
    initial_sidebar_state="collapsed"
)

# Hide ALL Streamlit UI elements so the HTML takes full screen
st.markdown("""
<style>
#MainMenu, header, footer, [data-testid="stToolbar"],
[data-testid="stSidebar"], [data-testid="collapsedControl"],
.stDeployButton, #stDecoration { display: none !important; }
.main .block-container {
    padding: 0 !important;
    margin: 0 !important;
    max-width: 100% !important;
}
.main { padding: 0 !important; }
iframe { border: none !important; }
</style>
""", unsafe_allow_html=True)

# The full HTML system encoded in base64
HTML_B64 = """"""

html_decoded = base64.b64decode(HTML_B64).decode('utf-8')

# Render full-screen via iframe using srcdoc
st.components.v1.html(html_decoded, height=900, scrolling=True)
